const raw = $input.first().json;
let text = '';
if (raw.content && raw.content.parts) {
  text = raw.content.parts[0].text;
} else if (typeof raw === 'string') {
  text = raw;
} else if (raw.text) {
  text = raw.text;
} else {
  text = JSON.stringify(raw);
}

const cleanText = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const data = JSON.parse(cleanText);

if (!data.scenes || data.scenes.length < 3) {
  throw new Error('scenes must have at least 3 items, got: ' + (data.scenes?.length || 0));
}

// dialogue_turns 검증
for (let i = 0; i < data.scenes.length; i++) {
  const scene = data.scenes[i];
  if (!scene.dialogue_turns || scene.dialogue_turns.length < 2) {
    if (scene.dialogue && scene.speaker) {
      scene.dialogue_turns = [{speaker: scene.speaker, line: scene.dialogue}];
    } else {
      throw new Error('scene ' + (i+1) + ' missing dialogue_turns');
    }
  }
  if (!scene.dialogue) {
    scene.dialogue = scene.dialogue_turns.map(t => t.line).join(' ');
  }
  if (!scene.speaker) {
    scene.speaker = scene.dialogue_turns[0].speaker;
  }
}

return [{
  json: {
    hook_title: data.hook_title,
    scenes: data.scenes,
    Subject: data.Subject,
    Caption: data.Caption,
    Comment: data.Comment,
    BGM_prompt: data.BGM_prompt,
    fullDialogue: data.scenes.map(s => s.dialogue).join(' '),
    segmentCount: data.scenes.length,
    Status: '준비',
    generatedAt: new Date().toISOString()
  }
}];

const data = $('콘텐츠 파싱').first().json;
const scenes = data.scenes || [];

// 고정 참조 이미지 URL
const refResults = $('참조 이미지 프롬프트').all();
const refA_url = refResults[0]?.json?.refUrl || '';
const refB_url = refResults[1]?.json?.refUrl || '';

if (!refA_url || !refB_url) {
  throw new Error('참조 이미지 URL 없음! refA=' + !!refA_url + ', refB=' + !!refB_url);
}

// Veo3 핑퐁 대화 프롬프트 생성
function buildVeo3Dialogue(turns) {
  const speakerDesc = {
    'A': 'The man in the black hoodie with gold chain (short fade haircut)',
    'B': 'The man in the white t-shirt with silver watch (twists hairstyle)'
  };

  return turns.map((turn, i) => {
    const desc = speakerDesc[turn.speaker] || speakerDesc['A'];
    const line = turn.line.replace(/'/g, "");
    if (i === 0) return desc + " says '" + line + "'";
    return "then " + desc + " responds '" + line + "'";
  }).join(', ');
}

return scenes.map((scene, i) => {
  const speaker = scene.speaker || scene.dialogue_turns?.[0]?.speaker || 'A';

  const cleanImagePrompt = scene.image_prompt.replace(/"/g, "'");

  // dialogue_turns 핑퐁 프롬프트
  let dialoguePart;
  if (scene.dialogue_turns && scene.dialogue_turns.length > 1) {
    dialoguePart = buildVeo3Dialogue(scene.dialogue_turns);
  } else {
    const cleanDialogue = scene.dialogue.replace(/"/g, "'");
    dialoguePart = 'The person is naturally speaking in Korean, saying: ' + cleanDialogue;
  }

  const veo3_prompt = cleanImagePrompt +
    '. ' + dialoguePart +
    '. Natural back-and-forth conversation with realistic timing. Natural lip synchronization for both speakers, subtle body gestures while talking, cinematic camera movement. No text overlay, no subtitles, no captions on screen.';

  return {
    json: {
      index: i,
      dialogue: scene.dialogue,
      dialogue_turns: scene.dialogue_turns || [{speaker: speaker, line: scene.dialogue}],
      image_prompt: scene.image_prompt,
      veo3_prompt: veo3_prompt,
      speaker: speaker,
      refUrl_A: refA_url,
      refUrl_B: refB_url,
    }
  };
});

// NCA 스토리형 숏츠 - 실패한 영상 스킵
const hookTitle = $('콘텐츠 파싱').first().json.hook_title;
const segmentCount = $('콘텐츠 파싱').first().json.segmentCount;

let segments = [];
let currentStart = 0;
const CLIP_DURATION = 8;

function getVideoUrl(nodeName) {
  try {
    const data = $(nodeName).first().json;
    return data?.data?.response?.resultUrls?.[0] || '';
  } catch(e) { return ''; }
}

let skippedVideos = [];
for (let i = 0; i < segmentCount; i++) {
  const videoUrl = getVideoUrl('영상' + (i + 1) + ' 결과');
  const segData = $('세그먼트 분리').all()[i]?.json;
  const dialogueText = segData?.dialogue
    || (segData?.dialogue_turns || []).map(t => t.line).join(' ') || '';

  if (!videoUrl) {
    console.log('영상' + (i+1) + ' URL 없음 → 스킵');
    skippedVideos.push(i + 1);
    continue;
  }

  segments.push({
    index: i + 1, videoUrl, duration: CLIP_DURATION,
    start: currentStart, dialogueText,
  });
  currentStart += CLIP_DURATION;
}

if (segments.length === 0) {
  throw new Error('모든 영상 생성 실패 - 합성 불가');
}

const totalDuration = currentStart;

function toSrtTime(sec) {
  const h = Math.floor(sec / 3600);
  const m = Math.floor((sec % 3600) / 60);
  const s = Math.floor(sec % 60);
  const ms = Math.round((sec - Math.floor(sec)) * 1000);
  return String(h).padStart(2, '0') + ':' +
         String(m).padStart(2, '0') + ':' +
         String(s).padStart(2, '0') + ',' +
         String(ms).padStart(3, '0');
}

let srtLines = [];
for (let i = 0; i < segments.length; i++) {
  const seg = segments[i];
  srtLines.push((i + 1) + '\n' + toSrtTime(seg.start) + ' --> ' +
    toSrtTime(seg.start + seg.duration) + '\n' + seg.dialogueText + '\n');
}
const srtContent = srtLines.join('\n');

let inputs = [];
let inputIndex = 0;
const videoInputs = [];

for (const seg of segments) {
  inputs.push({ file_url: seg.videoUrl, options: [] });
  videoInputs.push(inputIndex);
  inputIndex++;
}

let filterParts = [];
for (let i = 0; i < segments.length; i++) {
  const vIdx = videoInputs[i];
  filterParts.push(
    '[' + vIdx + ':v]trim=duration=' + segments[i].duration +
    ',setpts=PTS-STARTPTS,scale=1920:1080:force_original_aspect_ratio=decrease' +
    ',pad=1920:1080:(ow-iw)/2:(oh-ih)/2:black,fps=30[v' + i + ']'
  );
  filterParts.push(
    '[' + vIdx + ':a]atrim=duration=' + segments[i].duration +
    ',asetpts=PTS-STARTPTS[a' + i + ']'
  );
}

filterParts.push(segments.map((_, i) => '[v' + i + ']').join('') +
  'concat=n=' + segments.length + ':v=1:a=0[vfinal]');
filterParts.push(segments.map((_, i) => '[a' + i + ']').join('') +
  'concat=n=' + segments.length + ':v=0:a=1[afinal]');

const nca_payload = {
  inputs, filters: [{ filter: filterParts.join(';') }],
  outputs: [{
    options: [
      { option: '-map', argument: '[vfinal]' },
      { option: '-map', argument: '[afinal]' },
      { option: '-c:v', argument: 'libx264' },
      { option: '-preset', argument: 'medium' },
      { option: '-crf', argument: '18' },
      { option: '-c:a', argument: 'aac' },
      { option: '-b:a', argument: '256k' },
      { option: '-pix_fmt', argument: 'yuv420p' },
      { option: '-movflags', argument: '+faststart' },
      { option: '-t', argument: String(totalDuration) }
    ],
    file_name: 'story_shorts_final.mp4'
  }]
};


// ★ 추가: 자막용 턴별 대사 데이터 수집
const dialogueData = [];
for (const seg of segments) {
  const segData = $('세그먼트 분리').all()[seg.index - 1]?.json;
  const turns = segData?.dialogue_turns || [];
  dialogueData.push({
    start: seg.start,
    duration: seg.duration,
    turns: turns.map(t => ({ speaker: t.speaker, line: t.line }))
  });
}

return [{
  json: {
    nca_payload, totalDuration, srtContent,
    segmentCount: segments.length, hookTitle,
    skippedVideos,
    dialogueData,
    subject: $('콘텐츠 파싱').first().json.Subject,
    caption: $('콘텐츠 파싱').first().json.Caption,
    comment: $('콘텐츠 파싱').first().json.Comment,
  }
}];

// NCA 결과 처리
const result = $input.first().json;
const prevData = $('NCA 데이터 준비').first().json;

let videoUrl = '';
if (Array.isArray(result.response)) {
  videoUrl = result.response[0]?.file_url || '';
} else if (typeof result.response === 'string') {
  videoUrl = result.response;
} else {
  videoUrl = result.output_url || result.url || result.video_url || result.file_url || '';
}

if (!videoUrl) {
  throw new Error('NCA 영상 제작 결과 URL 없음: ' + JSON.stringify(result).substring(0, 500));
}

return [{
  json: {
    final_video_url: videoUrl,
    url: videoUrl,
    hookTitle: prevData.hookTitle || '',
    dialogueData: prevData.dialogueData || [],
    totalDuration: prevData.totalDuration || 24,
    srtContent: prevData.srtContent,
    subject: prevData.subject,
    caption: prevData.caption,
    comment: prevData.comment,
  }
}];

// 고정 참조 이미지 URL
const refA_url = "https://raw.githubusercontent.com/hatihoro15-netizen/n8n-project/feature/jay-mike-character/Jay.png";
const refB_url = "https://raw.githubusercontent.com/hatihoro15-netizen/n8n-project/feature/jay-mike-character/Mike.png";
return [
  { json: { refUrl: refA_url, speaker: "A" } },
  { json: { refUrl: refB_url, speaker: "B" } }
];

// 이미지 URL 추출 (크레덴셜 기반 폴링)
const staticData = $getWorkflowStaticData('node');
if (!staticData.retryCount) staticData.retryCount = 0;
staticData.retryCount++;

const data = $input.first().json;
let imageUrl = '';

// 결과에서 URL 추출
if (data?.data?.state === 'success' && data?.data?.resultJson) {
  try {
    const parsed = JSON.parse(data.data.resultJson);
    imageUrl = (parsed.resultUrls || parsed.originUrls || [])[0] || '';
  } catch(e) {}
}

// 실패 확인
if (data?.data?.state === 'failed') {
  staticData.retryCount = 0;
  throw new Error('이미지 생성 실패: ' + (data?.data?.taskId || ''));
}

if (imageUrl) {
  staticData.retryCount = 0;
  return [{ json: { ...data, images: [{ url: imageUrl }], imageComplete: true } }];
}

// 타임아웃 (30회 × 30초 = 15분)
if (staticData.retryCount > 30) {
  staticData.retryCount = 0;
  throw new Error('이미지 URL 추출 실패 (15분 타임아웃)');
}

// 미완료
return [{ json: { ...data, imageComplete: false } }];

// 장면 1의 이미지 프롬프트만 선택 (1장만 생성)
const items = $input.all();
const first = items[0].json;
return [{
  json: {
    image_prompt: first.image_prompt,
    refUrl_A: first.refUrl_A,
    refUrl_B: first.refUrl_B,
  }
}];

// 영상1 준비: 이미지 URL 추출 결과에서 이미지 가져오기
const imageUrl = $input.first().json.images?.[0]?.url || '';
if (!imageUrl) throw new Error('이미지 URL 없음');

const seg = $('세그먼트 분리').all()[0].json;
const prompt = (seg.veo3_prompt || '').replace(/[\\"]/g, "'").replace(/[\n\r\t]/g, ' ').trim();
if (!prompt) throw new Error('veo3_prompt 없음 (장면1)');

return [{
  json: {
    veo3Body: {
      prompt: prompt,
      imageUrls: [imageUrl],
      model: 'veo3_fast',
      generationType: 'FIRST_AND_LAST_FRAMES_2_VIDEO',
      aspect_ratio: '16:9',
      enableTranslation: false
    }
  }
}];

// 프레임1 추출 (재진입 지원)
const data = $input.first().json;

// 영상 실패 시 스킵
if (data.videoFailed) {
  console.log('영상 실패 → 프레임 추출 스킵');
  return [{ json: { skipped: true, originalImageUrl: data.originalImageUrl || '' } }];
}

// 영상 URL: 첫 진입이면 결과에서, 재시도면 전달받은 videoUrl
const videoUrl = data.videoUrl || data?.data?.response?.resultUrls?.[0] || '';
if (!videoUrl) {
  console.log('영상 URL 없음 → 프레임 추출 스킵');
  return [{ json: { skipped: true } }];
}

// NCA API로 7.5초 시점 프레임 추출 (jpg 강제)
try {
  const result = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://76.13.182.180:8080/v1/ffmpeg/compose',
    headers: {
      'x-api-key': 'nca-sagong-2026',
      'Content-Type': 'application/json'
    },
    body: {
      inputs: [{ file_url: videoUrl, options: [{ option: '-ss', argument: '7.5' }] }],
      filters: [],
      outputs: [{
        options: [
          { option: '-frames:v', argument: '1' },
          { option: '-q:v', argument: '2' },
          { option: '-f', argument: 'image2' },
          { option: '-update', argument: '1' }
        ],
        file_name: 'last_frame_1.jpg'
      }]
    }
  });
  return [{ json: { ...result, videoUrl } }];
} catch(e) {
  console.log('NCA 프레임 추출 실패: ' + e.message);
  return [{ json: { ncaError: true, error: e.message, videoUrl } }];
}

// 프레임1 결과 (완료 체크 + mp4 폴백)
const staticData = $getWorkflowStaticData('node');
if (!staticData.retryCount) staticData.retryCount = 0;

const data = $input.first().json;
const originalImageUrl = $('이미지 URL 추출').first().json?.images?.[0]?.url || '';

// 스킵된 경우 바로 완료
if (data.skipped) {
  staticData.retryCount = 0;
  const fallback = data.originalImageUrl || originalImageUrl;
  return [{ json: { frameUrl: fallback, frameComplete: true, usedFallback: true } }];
}

let frameUrl = '';

// NCA 응답에서 프레임 URL 추출
if (!data.ncaError) {
  if (Array.isArray(data?.response)) {
    frameUrl = data.response[0]?.file_url || '';
  }
  if (!frameUrl && data?.file_url) frameUrl = data.file_url;
  if (!frameUrl && data?.url) frameUrl = data.url;
}

// .mp4 URL이면 이미지가 아니므로 원본 이미지로 폴백
if (frameUrl && frameUrl.toLowerCase().endsWith('.mp4')) {
  console.log('프레임1 결과가 .mp4 → 원본 이미지 폴백: ' + frameUrl);
  staticData.retryCount = 0;
  return [{ json: { frameUrl: originalImageUrl, frameComplete: true, usedFallback: true, mp4Detected: true } }];
}

if (frameUrl) {
  staticData.retryCount = 0;
  return [{ json: { frameUrl, frameComplete: true } }];
}

// 재시도 횟수 체크 (10회 × 60초 = 약 10분)
staticData.retryCount++;
if (staticData.retryCount > 10) {
  console.log('프레임1 추출 10회 실패 → 원본 이미지 폴백');
  staticData.retryCount = 0;
  return [{ json: { frameUrl: originalImageUrl, frameComplete: true, usedFallback: true } }];
}

// 미완료 → 재시도
console.log('프레임1 미완료, 재시도 ' + staticData.retryCount + '/10');
return [{ json: { frameComplete: false, videoUrl: data.videoUrl || '' } }];

// 영상2 준비: 프레임1 또는 원본 이미지 폴백
let imageUrl = $input.first().json.frameUrl || '';

if (!imageUrl) {
  imageUrl = $('이미지 URL 추출').first().json?.images?.[0]?.url || '';
  console.log('프레임 없음 → 원본 이미지 폴백');
}
if (!imageUrl) throw new Error('영상2 입력 이미지 없음');

const seg = $('세그먼트 분리').all()[1].json;
const prompt = (seg.veo3_prompt || '').replace(/[\\"]/g, "'").replace(/[\n\r\t]/g, ' ').trim();
if (!prompt) throw new Error('veo3_prompt 없음 (장면2)');

return [{
  json: {
    veo3Body: {
      prompt: prompt,
      imageUrls: [imageUrl],
      model: 'veo3_fast',
      generationType: 'FIRST_AND_LAST_FRAMES_2_VIDEO',
      aspect_ratio: '16:9',
      enableTranslation: false
    }
  }
}];

// 프레임2 추출 (재진입 지원)
const data = $input.first().json;

// 영상 실패 시 스킵
if (data.videoFailed) {
  console.log('영상 실패 → 프레임 추출 스킵');
  return [{ json: { skipped: true, originalImageUrl: data.originalImageUrl || '' } }];
}

// 영상 URL: 첫 진입이면 결과에서, 재시도면 전달받은 videoUrl
const videoUrl = data.videoUrl || data?.data?.response?.resultUrls?.[0] || '';
if (!videoUrl) {
  console.log('영상 URL 없음 → 프레임 추출 스킵');
  return [{ json: { skipped: true } }];
}

// NCA API로 7.5초 시점 프레임 추출 (jpg 강제)
try {
  const result = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://76.13.182.180:8080/v1/ffmpeg/compose',
    headers: {
      'x-api-key': 'nca-sagong-2026',
      'Content-Type': 'application/json'
    },
    body: {
      inputs: [{ file_url: videoUrl, options: [{ option: '-ss', argument: '7.5' }] }],
      filters: [],
      outputs: [{
        options: [
          { option: '-frames:v', argument: '1' },
          { option: '-q:v', argument: '2' },
          { option: '-f', argument: 'image2' },
          { option: '-update', argument: '1' }
        ],
        file_name: 'last_frame_2.jpg'
      }]
    }
  });
  return [{ json: { ...result, videoUrl } }];
} catch(e) {
  console.log('NCA 프레임 추출 실패: ' + e.message);
  return [{ json: { ncaError: true, error: e.message, videoUrl } }];
}

// 프레임2 결과 (완료 체크 + mp4 폴백)
const staticData = $getWorkflowStaticData('node');
if (!staticData.retryCount) staticData.retryCount = 0;

const data = $input.first().json;
const originalImageUrl = $('이미지 URL 추출').first().json?.images?.[0]?.url || '';

// 스킵된 경우 바로 완료
if (data.skipped) {
  staticData.retryCount = 0;
  const fallback = data.originalImageUrl || originalImageUrl;
  return [{ json: { frameUrl: fallback, frameComplete: true, usedFallback: true } }];
}

let frameUrl = '';

// NCA 응답에서 프레임 URL 추출
if (!data.ncaError) {
  if (Array.isArray(data?.response)) {
    frameUrl = data.response[0]?.file_url || '';
  }
  if (!frameUrl && data?.file_url) frameUrl = data.file_url;
  if (!frameUrl && data?.url) frameUrl = data.url;
}

// .mp4 URL이면 이미지가 아니므로 원본 이미지로 폴백
if (frameUrl && frameUrl.toLowerCase().endsWith('.mp4')) {
  console.log('프레임2 결과가 .mp4 → 원본 이미지 폴백: ' + frameUrl);
  staticData.retryCount = 0;
  return [{ json: { frameUrl: originalImageUrl, frameComplete: true, usedFallback: true, mp4Detected: true } }];
}

if (frameUrl) {
  staticData.retryCount = 0;
  return [{ json: { frameUrl, frameComplete: true } }];
}

// 재시도 횟수 체크 (10회 × 60초 = 약 10분)
staticData.retryCount++;
if (staticData.retryCount > 10) {
  console.log('프레임2 추출 10회 실패 → 원본 이미지 폴백');
  staticData.retryCount = 0;
  return [{ json: { frameUrl: originalImageUrl, frameComplete: true, usedFallback: true } }];
}

// 미완료 → 재시도
console.log('프레임2 미완료, 재시도 ' + staticData.retryCount + '/10');
return [{ json: { frameComplete: false, videoUrl: data.videoUrl || '' } }];

// 영상3 준비: 프레임2 또는 원본 이미지 폴백
let imageUrl = $input.first().json.frameUrl || '';

if (!imageUrl) {
  imageUrl = $('이미지 URL 추출').first().json?.images?.[0]?.url || '';
  console.log('프레임 없음 → 원본 이미지 폴백');
}
if (!imageUrl) throw new Error('영상3 입력 이미지 없음');

const seg = $('세그먼트 분리').all()[2].json;
const prompt = (seg.veo3_prompt || '').replace(/[\\"]/g, "'").replace(/[\n\r\t]/g, ' ').trim();
if (!prompt) throw new Error('veo3_prompt 없음 (장면3)');

return [{
  json: {
    veo3Body: {
      prompt: prompt,
      imageUrls: [imageUrl],
      model: 'veo3_fast',
      generationType: 'FIRST_AND_LAST_FRAMES_2_VIDEO',
      aspect_ratio: '16:9',
      enableTranslation: false
    }
  }
}];

// 영상1 실패/타임아웃 체크 (원본 이미지 폴백)
const staticData = $getWorkflowStaticData('node');
